export const TYPEN = ["Ökodorf", "Kommune", "Kollektiv", "Spirituelle Gemeinschaft", "Wohnprojekt"]

export function getTypBadge(typ) {
  const map = {
    "Ökodorf": "badge-oeko",
    "Kommune": "badge-kommune",
    "Kollektiv": "badge-kollektiv",
    "Spirituelle Gemeinschaft": "badge-spirituell",
    "Wohnprojekt": "badge-wohn",
  }
  return map[typ] || "badge-oeko"
}

export function getStatusInfo(status) {
  const map = {
    "aktiv": { label: "Aktiv auf Communet", color: "#2d6a4f", bg: "#e8f5ee", icon: "🟢" },
    "einrichtung": { label: "Profil in Einrichtung", color: "#7c4a0a", bg: "#fff3e0", icon: "🟡" },
    "nicht-registriert": { label: "Noch nicht registriert", color: "#6b6b63", bg: "#f0f0ee", icon: "⚫" },
  }
  return map[status] || map["nicht-registriert"]
}

export function getBesucher(besucher) {
  const map = {
    "offen":      { label: "Besucher willkommen",        label_en: "Visitors welcome",         icon: "🟢", color: "#2d6a4f", bg: "#e8f5ee" },
    "anmeldung":  { label: "Nach Anmeldung",             label_en: "By appointment",           icon: "🟡", color: "#7c4a0a", bg: "#fff3e0" },
    "volontaere": { label: "Nur Volontäre",              label_en: "Volunteers only",          icon: "🔵", color: "#303f9f", bg: "#e8eaf6" },
    "einladung":  { label: "Nur auf Einladung",          label_en: "Invitation only",          icon: "🟠", color: "#e65100", bg: "#fff3e0" },
    "geschlossen":{ label: "Keine Besucher",             label_en: "Closed community",         icon: "🔴", color: "#880e4f", bg: "#fce4ec" },
    "unbekannt":  { label: "Unbekannt — bitte anfragen", label_en: "Unknown — please enquire", icon: "⚪", color: "#6b6b63", bg: "#f0f0ee" },
  }
  return map[besucher] || map["unbekannt"]
}

